export const meta = { name: 'parallel_primality_synthesis', description: 'Run two independent primality checks for 17 and synthesize surviving evidence.', phases: [{ title: 'Independent checks' }, { title: 'Synthesis' }] };

phase('Independent checks');
const checks = await parallel([
  () => agent('Independently determine whether 17 is prime. Give a concise, verifiable justification and label it checker A.'),
  () => agent('Independently determine whether 17 is prime. Give a concise, verifiable justification using a different framing if possible and label it checker B.')
]);

const surviving = [];
const failedChecks = [];
for (let i = 0; i < checks.length; i++) {
  const value = checks[i];
  if (value && String(value).trim()) surviving.push({ checker: i === 0 ? 'A' : 'B', result: String(value) });
  else failedChecks.push(i === 0 ? 'A' : 'B');
}

phase('Synthesis');
const synthesis = await agent(`Synthesize the following surviving independent evidence about whether 17 is prime. Return ONLY a compact JSON object with keys prime (boolean), evidence (array of concise strings), and failedChecks (array). Do not add markdown.\nEvidence: ${JSON.stringify(surviving)}\nFailed checks: ${JSON.stringify(failedChecks)}`);
log(synthesis);

